public String robotSort(String s) {
    StringBuilder sb = new StringBuilder();
    for (char c : s.toCharArray()) {
        while (sb.length() > 0 && sb.charAt(sb.length() - 1) <= c) {
            sb.setLength(sb.length() - 1);
        }
        sb.append(c);
    }
    return sb.toString();
}
